def filter(df, params):
    import json
    min_c = params.get('min_conf', 0)
    max_c = params.get('max_conf', 1)
    def max_conf(ext_val):
        try:
            obj = json.loads(ext_val) if isinstance(ext_val, str) else ext_val
            preds = obj.get('original_predictions', []) if isinstance(obj, dict) else obj
            if isinstance(preds, list):
                confs = [p.get('confidence',0) for p in preds if isinstance(p, dict)]
                return max(confs) if confs else 0
            return 0
        except:
            return 0
    df['_max_conf'] = df['ext'].apply(max_conf)
    result = df[(df['_max_conf'] >= min_c) & (df['_max_conf'] <= max_c)]
    return result.drop(columns=['_max_conf'], errors='ignore')
